    let map: HashMap<&str, i32> = keys.into_iter().zip(values).collect();
    println!("{}", map["b"]);
}

use std::collections::HashMap;

fn char_frequency(s: &str) -> HashMap<char, usize> {
    let mut map = HashMap::new();
    for c in s.chars() {
        *map.entry(c).or_insert(0) += 1;
    }
    map
}

fn main() {
    let freq = char_frequency("mississippi");
    let mut pairs: Vec<(char, usize)> = freq.into_iter().collect();
    pairs.sort();
    for (c, n) in pairs {
        println!("{}: {}", c, n);
    }
}

use std::collections::HashMap;

fn main() {
    let mut db: HashMap<&str, HashMap<&str, i32>> = HashMap::new();
    db.entry("alice").or_default().insert("math", 95);
    db.entry("alice").or_default().insert("english", 88);
    db.entry("bob").or_default().insert("math", 72);
    for (student, grades) in &db {
        for (subject, score) in grades {
            println!("{} {}: {}", student, subject, score);
        }
    }
}

use std::collections::HashMap;

fn main() {
    // Vec: ordered list of items
    let todo: Vec<&str> = vec!["write tests", "fix bug", "deploy"];
    println!("first task: {}", todo[0]);

    // HashMap: look up by name
    let mut config: HashMap<&str, &str> = HashMap::new();
    config.insert("host", "localhost");
    config.insert("port", "8080");
    println!("host: {}", config["host"]);
}
